const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const force = body.force === true;
let mode='power', reverifyDays=90;
try{ const s=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/settings/records',qs:{filter:'key="reoon"',perPage:1},headers:pbH,json:true}); const v=(s.items&&s.items[0]&&s.items[0].value)||{}; if(v.mode)mode=v.mode; if(v.reverify_days!=null)reverifyDays=v.reverify_days; }catch(e){}
const cutoffMs = Date.now() - (reverifyDays*86400000);
let contacts=[];
if(Array.isArray(body.ids) && body.ids.length){
  for(const id of body.ids){ try{ const c=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records/'+id,headers:pbH,json:true}); contacts.push(c); }catch(e){} }
} else {
  const filter=body.filter||''; let page=1;
  while(true){ const qs=Object.assign({perPage:500,page},filter?{filter}:{}); const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs,headers:pbH,json:true}); contacts=contacts.concat(r.items||[]); if(page>=(r.totalPages||1))break; page++; }
}
const out=[]; const seen=new Set();
for(const c of contacts){ if(!c.email||seen.has(c.email)) continue; const vAt=c.verified_at? new Date(String(c.verified_at).replace(' ','T')).getTime():0; if(!force && vAt && vAt>cutoffMs) continue; seen.add(c.email); out.push({json:{id:c.id,email:c.email,mode}}); }
return out;

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const picks=$('Pick contacts').all();
const results=$input.all();
const now=new Date().toISOString();
function mapStatus(s){ s=(s||'').toString().toLowerCase();
  if(s==='safe'||s==='role_account') return 'verified';
  if(s==='catch_all') return 'catch_all';
  if(['invalid','disabled','disposable','spamtrap','inbox_full','undeliverable'].includes(s)) return 'undeliverable';
  return 'unknown'; }
const counts={verified:0,undeliverable:0,catch_all:0,unknown:0};
for(let i=0;i<picks.length;i++){
  const id=picks[i].json.id;
  const r=(results[i]&&results[i].json)||{};
  const vs=mapStatus(r.status);
  counts[vs]=(counts[vs]||0)+1;
  try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+id,headers:pbH,body:{verification_status:vs,verified_at:now},json:true}); }catch(e){}
}
try{ const s=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/settings/records',qs:{filter:'key="reoon"',perPage:1},headers:pbH,json:true}); const rec=s.items&&s.items[0]; if(rec){ const v=rec.value||{}; v.last_run=now; await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/settings/records/'+rec.id,headers:pbH,body:{value:v},json:true}); } }catch(e){}
return [{json:{verified:counts.verified,undeliverable:counts.undeliverable,catch_all:counts.catch_all,unknown:counts.unknown,total:picks.length}}];
